import React from 'react';
import "./Home.css"

const Home = () => {
    return (
        <div className="contenedor">

            <aside>
                {/* Sidebar con categorías */}
                <h2>Categorías</h2>
                <ul>
                    <li>Lechería</li>
                    <li>Genética</li>
                    <li>Engorde</li>
                    <li>Corrales</li>
                    <li>Personal</li>
                    <li>Rentabilidad</li>
                    <li>Ventas</li>
                </ul>
            </aside>
            <main>
                {/* Contenido principal */}
                <h1>Mi Aplicación</h1>
                <p>Contenido principal...</p>
            </main>
        </div>
    );
}

export default Home;
